// ============================================================================
// PipelineHealthReport - checkStageHealth
// ============================================================================

describe('PipelineHealthReport.checkStageHealth', () => {
  const report = new PipelineHealthReport()

  it('should return health status for valid stage taskify', () => {
    const health = report.checkStageHealth('taskify')
    expect(health).toHaveProperty('status')
    expect(health).toHaveProperty('message')
    expect(health).toHaveProperty('timestamp')
    expect(['pass', 'fail', 'warn']).toContain(health.status)
    expect(typeof health.message).toBe('string')
    expect(health.timestamp).toBeInstanceOf(Date)
  })

  it('should return health status for valid stage architect', () => {
    const health = report.checkStageHealth('architect')
    expect(health.status).toBeDefined()
    expect(health.message).toBeDefined()
    expect(health.timestamp).toBeInstanceOf(Date)
  })

  it('should return health status for valid stage build', () => {
    const health = report.checkStageHealth('build')
    expect(health.status).toBeDefined()
    expect(health.timestamp).toBeInstanceOf(Date)
  })

  it('should throw Zod validation error for invalid stage name', () => {
    expect(() => report.checkStageHealth('invalid-stage')).toThrow()
  })

  it('should throw Zod validation error for empty string', () => {
    expect(() => report.checkStageHealth('')).toThrow()
  })

  it('should throw Zod validation error for stage with special characters', () => {
    expect(() => report.checkStageHealth('stage@#$')).toThrow()
  })
})

// ============================================================================
// PipelineHealthReport - generateReport
// ============================================================================

describe('PipelineHealthReport.generateReport', () => {
  const report = new PipelineHealthReport()

  it('should return a report object', () => {
    const result = report.generateReport()
    expect(result).toBeDefined()
  })

  it('should have overallHealth field', () => {
    const result = report.generateReport()
    expect(result).toHaveProperty('overallHealth')
    expect(['healthy', 'degraded', 'unhealthy']).toContain(result.overallHealth)
  })

  it('should have stageStatuses as Record', () => {
    const result = report.generateReport()
    expect(result).toHaveProperty('stageStatuses')
    expect(typeof result.stageStatuses).toBe('object')
  })

  it('should have generatedAt as Date', () => {
    const result = report.generateReport()
    expect(result).toHaveProperty('generatedAt')
    expect(result.generatedAt).toBeInstanceOf(Date)
  })

  it('should include taskify in stageStatuses', () => {
    const result = report.generateReport()
    expect(result.stageStatuses).toHaveProperty('taskify')
  })

  it('should include architect in stageStatuses', () => {
    const result = report.generateReport()
    expect(result.stageStatuses).toHaveProperty('architect')
  })

  it('should include build in stageStatuses', () => {
    const result = report.generateReport()
    expect(result.stageStatuses).toHaveProperty('build')
  })

  it('should include all known stages in stageStatuses', () => {
    const result = report.generateReport()
    const knownStages = [
      'taskify',
      'gap',
      'clarify',
      'architect',
      'plan-gap',
      'test',
      'build',
      'commit',
      'review',
      'fix',
      'verify',
      'docs',
      'pr',
    ]
    for (const stage of knownStages) {
      expect(result.stageStatuses).toHaveProperty(stage)
    }
  })

  it('should set overallHealth to healthy when all stages pass', () => {
    // This test verifies the overallHealth derivation logic
    const result = report.generateReport()
    expect(['healthy', 'degraded', 'unhealthy']).toContain(result.overallHealth)
  })
})

// ============================================================================
// PipelineHealthReport - getRetryRecommendation
// ============================================================================

describe('PipelineHealthReport.getRetryRecommendation', () => {
  const report = new PipelineHealthReport()

  it('should return RetryStrategy for valid failed stage', () => {
    const strategy = report.getRetryRecommendation('taskify')
    expect(strategy).toHaveProperty('shouldRetry')
    expect(strategy).toHaveProperty('maxRetries')
    expect(strategy).toHaveProperty('backoffMultiplier')
    expect(typeof strategy.shouldRetry).toBe('boolean')
    expect(typeof strategy.maxRetries).toBe('number')
    expect(typeof strategy.backoffMultiplier).toBe('number')
  })

  it('should return RetryStrategy for failed build stage', () => {
    const strategy = report.getRetryRecommendation('build')
    expect(strategy.shouldRetry).toBeDefined()
    expect(strategy.maxRetries).toBeGreaterThanOrEqual(0)
    expect(strategy.backoffMultiplier).toBeGreaterThan(0)
  })

  it('should return RetryStrategy for failed architect stage', () => {
    const strategy = report.getRetryRecommendation('architect')
    expect(strategy.shouldRetry).toBeDefined()
    expect(strategy.maxRetries).toBeDefined()
    expect(strategy.backoffMultiplier).toBeDefined()
  })

  it('should throw Zod validation error for invalid failedStage name', () => {
    expect(() => report.getRetryRecommendation('not-a-stage')).toThrow()
  })

  it('should throw Zod validation error for empty string', () => {
    expect(() => report.getRetryRecommendation('')).toThrow()
  })

  it('should throw Zod validation error for malformed stage name', () => {
    expect(() => report.getRetryRecommendation('build!')).toThrow()
  })

  it('should return non-zero maxRetries for retryable stages', () => {
    const strategy = report.getRetryRecommendation('build')
    // build stage should be retryable
    expect(strategy.maxRetries).toBeGreaterThan(0)
  })

  it('should return backoffMultiplier greater than 1 for exponential backoff', () => {
    const strategy = report.getRetryRecommendation('build')
    // exponential backoff should have multiplier > 1
    expect(strategy.backoffMultiplier).toBeGreaterThan(1)
  })
})

// ============================================================================
// Type exports
// ============================================================================

describe('Type exports', () => {
  it('should export HealthStatus type', () => {
    // Type-level test - verifies the type is exported
    const _healthStatus: HealthStatus = {
      status: 'pass',
      message: 'ok',
      timestamp: new Date(),
    }
    expect(_healthStatus.status).toBe('pass')
  })

  it('should export Report type', () => {
    // Type-level test - verifies the type is exported
    const _report: Report = {
      overallHealth: 'healthy',
      stageStatuses: {},
      generatedAt: new Date(),
    }
    expect(_report.overallHealth).toBe('healthy')
  })

  it('should export RetryStrategy type', () => {
    // Type-level test - verifies the type is exported
    const _strategy: RetryStrategy = {
      shouldRetry: true,
      maxRetries: 3,
      backoffMultiplier: 2,
    }
    expect(_strategy.shouldRetry).toBe(true)
  })
})
